import dayjs from 'dayjs'; // npm install dayjs (es mejor para manejar horas)

export const processLogisticsData = (datos) => {
  if (!datos || datos.length === 0) return null;

  // 1. KPIs GLOBALES
  const total = datos.length;
  // Consideramos "Bipeo/Etiquetado" si tiene fecha de impresión de etiqueta
  const piezasEtiquetadas = datos.filter(d => d['Labeling Date Printed']).length;
  const pendientes = total - piezasEtiquetadas;
  const eficiencia = total > 0 ? ((piezasEtiquetadas / total) * 100).toFixed(2) : "0.00";

  // 2. DATOS PARA LA GRÁFICA (Por horas)
  // Agrupamos por la hora de 'Inbound Date Closed' (Arribo) y 'Labeling Date Printed' (Bipeo)
  const chartMap = {};
  const franjasInteres = ["05:00", "07:00", "09:00", "11:00", "13:00", "15:00", "17:00", "19:00"];

  franjasInteres.forEach(h => chartMap[h] = { hora: h, arribo: 0, bipeo: 0 });

  datos.forEach(row => {
    const horaArribo = row['Inbound Date Closed'] ? dayjs(row['Inbound Date Closed']).format('HH:00') : null;
    const horaBipeo = row['Labeling Date Printed'] ? dayjs(row['Labeling Date Printed']).format('HH:00') : null;

    if (chartMap[horaArribo]) chartMap[horaArribo].arribo++;
    if (chartMap[horaBipeo]) chartMap[horaBipeo].bipeo++;
  });

  // 3. TABLA DE ARMADO DE HU (Intervalos)
  // Agrupamos por intervalos de una hora
  const tableData = franjasInteres.map(hora => {
    const inicio = dayjs(`2024-01-01 ${hora}`);
    const fin = inicio.add(1, 'hour');

    const enIntervalo = datos.filter(d => {
      const dHora = dayjs(d['Labeling Date Printed']);
      return dHora.isAfter(inicio) && dHora.isBefore(fin);
    });

    return {
      intervalo: `${hora} - ${fin.format('HH:00')}`,
      etiquetado: enIntervalo.length + Math.floor(Math.random() * 50), // Simulamos target
      piezas: enIntervalo.length,
      usuarios: [...new Set(enIntervalo.map(d => d['Inbound User ID']))].length || 0
    };
  });

  // 4. TARGETS POR CUTOFF
  // Agrupamos según la columna 'Cutoff' del CSV
  const targets = {
    "14HS": calculateTargetProgress(datos, "14:00"),
    "16HS": calculateTargetProgress(datos, "16:00"),
    "18HS": calculateTargetProgress(datos, "18:00"),
  };

  return {
    kpis: { total, piezasEtiquetadas, pendientes, eficiencia },
    chartData: Object.values(chartMap),
    tableData,
    targets
  };
};

const calculateTargetProgress = (datos, time) => {
  const totalCutoff = datos.filter(d => d['Cutoff']?.includes(time)).length;
  const listos = datos.filter(d => d['Cutoff']?.includes(time) && d['Labeling Date Printed']).length;
  return {
    percentage: totalCutoff > 0 ? Math.round((listos / totalCutoff) * 100) : 0,
    units: totalCutoff
  };
}
